 1	import * as React from 'react';
 2	import {
 3	  Dropdown,
 4	  DropdownItem,
 5	  DropdownList,
 6	  MenuToggle,
 7	  MenuToggleElement,
 8	} from '@patternfly/react-core';
 9	
10	type StaticDropdownProps = {
11	  onSelect: (selectedItem: string) => void;
12	  onBlur?: () => void;
13	  className?: string;
14	  required?: boolean;
15	  ariaLabel?: string;
16	  defaultSelection?: string;
17	  dropdownItems: {
18	    [key: string]: JSX.Element | string;
19	  };
20	  defaultText?: string;
21	  textGenerator?: (
22	    key: string,
23	    dropdownItems?: StaticDropdownProps['dropdownItems']
24	  ) => JSX.Element | string;
25	  'data-test'?: string;
26	  isDisabled?: boolean;
27	  isFullWidth?: boolean;
28	};
29	
30	const StaticDropdown: React.FC<StaticDropdownProps> = ({
31	  onSelect,
32	  className,
33	  defaultSelection = '',
34	  dropdownItems,
35	  defaultText = '',
36	  textGenerator,
37	  'data-test': dataTest,
38	  isDisabled = false,
39	  isFullWidth = false,
40	}) => {
41	  const [selectedItem, setSelectedItem] = React.useState(defaultSelection);
42	  const [isOpen, setOpen] = React.useState(false);
43	
44	  const onChange = (event?: React.SyntheticEvent<HTMLDivElement>) => {
45	    const key = event?.currentTarget?.id;
46	    if (key) {
47	      setSelectedItem(key);
48	      onSelect(key);
49	    }
50	    setSelectedItem(key);
51	    setOpen(false);
52	  };
53	
54	  const processedDropdownItems = React.useMemo(
55	    () =>
56	      Object.entries(dropdownItems).map(([k, v]) => (
57	        <DropdownItem key={k} id={k} data-test-dropdown-menu={v}>
58	          {v}
59	        </DropdownItem>
60	      )),
61	    [dropdownItems]
62	  );
63	
64	  const dropdownText =
65	    selectedItem && textGenerator
66	      ? textGenerator(selectedItem, dropdownItems)
67	      : selectedItem || defaultText;
68	
69	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
70	    <MenuToggle
71	      ref={toggleRef}
72	      onClick={() => setOpen((o) => !o)}
73	      isExpanded={isOpen}
74	      isDisabled={isDisabled}
75	      data-test={dataTest}
76	      isFullWidth={isFullWidth}
77	    >
78	      {dropdownText}
79	    </MenuToggle>
80	  );
81	
82	  return (
83	    <Dropdown
84	      className={className}
85	      isOpen={isOpen}
86	      onSelect={onChange}
87	      onOpenChange={(open: boolean) => setOpen(open)}
88	      toggle={toggle}
89	      popperProps={isFullWidth ? { width: 'trigger' } : undefined}
90	    >
91	      <DropdownList>{processedDropdownItems}</DropdownList>
92	    </Dropdown>
93	  );
94	};
95	
96	export default StaticDropdown;

